import React, { useState } from 'react';
import CameraList from './CameraList';
import CameraForm from './CameraForm';
import SimpleCameraForm from './SimpleCameraForm'; // Form đơn giản
import DrawingCanvas from './DrawingCanvas'; // Form vẽ
import './CameraManagement.css';

function CameraManagement() {
  const [activeTab, setActiveTab] = useState('cameras');
  const [selectedCamera, setSelectedCamera] = useState(null);
  const [cameras, setCameras] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [step, setStep] = useState(1); // 1: nhập URL, 2: vẽ
  const [cameraData, setCameraData] = useState({
    rtspUrl: '',
    image: null,
    imagePreview: null
  });

  const tabs = [
    { id: 'cameras', label: '📷 Cameras', icon: '📹' },
  ];

  const handleNewCamera = () => {
    setStep(1);
    setCameraData({
      rtspUrl: '',
      image: null,
      imagePreview: null
    });
    setShowModal(true);
  };

  const handleNextStep = (data) => {
    setCameraData(data);
    setStep(2);
  };

  const handleSaveCamera = async (config) => {
    // Tạo camera mới với config từ DrawingCanvas
    const newCamera = {
      cam_info: {
        url: cameraData.rtspUrl,
        cam_id: generateUUID()
      },
      config: config,
      image: cameraData.imagePreview
    };

    // Upload lên server
    const formData = new FormData();
    formData.append('rtspUrl', cameraData.rtspUrl);
    formData.append('payload', JSON.stringify({
      list_camera: [newCamera]
    }));
    if (cameraData.image) {
      formData.append('image', cameraData.image);
    }

    try {
      const response = await fetch('http://localhost:5000/api/cameras', {
        method: 'POST',
        body: formData
      });

      if (response.ok) {
        const savedCamera = await response.json();
        setCameras([...cameras, savedCamera]);
        setShowModal(false);
        setStep(1);
        alert('Thêm camera thành công!');
      } else {
        alert('Lỗi khi thêm camera');
      }
    } catch (error) {
      alert('Lỗi kết nối server');
    }
  };

  const generateUUID = () => {
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
      const r = Math.random() * 16 | 0;
      const v = c === 'x' ? r : (r & 0x3 | 0x8);
      return v.toString(16);
    });
  };

  return (
    <div className="camera-management">
      {/* Sidebar */}
      <div className="sidebar">
        <div className="logo">
          <h2>Camera Admin</h2>
          <span className="version">v2.0</span>
        </div>

        <nav className="nav-menu">
          {tabs.map(tab => (
            <button
              key={tab.id}
              className={`nav-item ${activeTab === tab.id ? 'active' : ''}`}
              onClick={() => setActiveTab(tab.id)}
            >
              <span className="nav-icon">{tab.icon}</span>
              <span className="nav-label">{tab.label}</span>
            </button>
          ))}
        </nav>

        <div className="sidebar-footer">
          <div className="server-status">
            <span className="status-dot"></span>
            <span>Server: Online</span>
          </div>
          <div className="camera-stats">
            <small>Total: {cameras.length} cameras</small>
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="main-content">
        <div className="content-header">
          <h1>Camera Management</h1>
          <div className="header-actions">
            <button 
              className="btn-primary"
              onClick={handleNewCamera}
            >
              + New Camera
            </button>
          </div>
        </div>

        <div className="content-area">
          {activeTab === 'cameras' && (
            <div className="cameras-view">
              {cameras.length > 0 ? (
                <CameraList 
                  cameras={cameras}
                  setCameras={setCameras}
                  onSelectCamera={(cam) => setSelectedCamera(cam)}
                />
              ) : (
                <div className="empty-state">
                  <p>Chưa có camera nào. Click "New Camera" để thêm mới.</p>
                </div>
              )}
            </div>
          )}
        </div>
      </div>

      {/* Modal */}
      {showModal && (
        <div className="modal-overlay">
          <div className="modal-content">
            <div className="modal-header">
              <h3>{step === 1 ? 'Thêm Camera Mới' : 'Vẽ Zone'}</h3>
              <button className="btn-close" onClick={() => setShowModal(false)}>×</button>
            </div>

            {step === 1 ? (
              <SimpleCameraForm 
                onNext={handleNextStep}
                onCancel={() => setShowModal(false)}
              />
            ) : (
              <DrawingCanvas 
                cameraData={cameraData}
                onSave={handleSaveCamera}
                onBack={() => setStep(1)}
              />
            )}
          </div>
        </div>
      )}
    </div>
  );
}

export default CameraManagement;
